1	import { useState } from "react";
2	import type { ConversationDto, ProjectDto } from "../types";
3	
4	export type View = "status" | "usage" | "models" | "chat";
5	
6	interface Props {
7	  view: View;
8	  setView: (v: View) => void;
9	  conversations: ConversationDto[];
10	  projects: ProjectDto[];
11	  activeConvId: number | null;
12	  onSelectConv: (id: number) => void;
13	  onNewChat: () => void;
14	  onSearch: (q: string) => void;
15	  onPin: (id: number, pinned: boolean) => void;
16	  onRename: (id: number, title: string) => void;
17	  onDelete: (id: number) => void;
18	  onCreateProject: () => void;
19	  onRenameProject: (id: number, name: string) => void;
20	  onDeleteProject: (id: number) => void;
21	  onPinProject: (id: number, pinned: boolean) => void;
22	  onMoveConv: (convId: number, projectId: number | null) => void;
23	  onOpenSettings: () => void;
24	}
25	
26	const NAV: { key: View; label: string; ico: string }[] = [
27	  { key: "status", label: "Status", ico: "▤" },
28	  { key: "usage", label: "Usage", ico: "◷" },
29	  { key: "models", label: "Models", ico: "◇" },
30	  { key: "chat", label: "Chat", ico: "✦" },
31	];
32	
33	const RT_BADGE: Record<string, string> = {
34	  omlx: "ML",
35	  llamaswap: "LS",
36	  llamacpp: "LC",
37	  vllm: "VL",
38	  openai: "AI",
39	};
40	
41	export function Sidebar(props: Props) {
42	  const [renaming, setRenaming] = useState<number | null>(null);
43	  const [renameBuf, setRenameBuf] = useState("");
44	  const [renamingProject, setRenamingProject] = useState<number | null>(null);
45	  const [projBuf, setProjBuf] = useState("");
46	  const [collapsed, setCollapsed] = useState<Set<number>>(new Set());
47	  const [dropTarget, setDropTarget] = useState<number | "loose" | null>(null);
48	
49	  const commitRename = (id: number) => {
50	    if (renameBuf.trim()) props.onRename(id, renameBuf.trim());
51	    setRenaming(null);
52	  };
53	  const commitProjectRename = (id: number) => {
54	    if (projBuf.trim()) props.onRenameProject(id, projBuf.trim());
55	    setRenamingProject(null);
56	  };
57	  const toggleCollapsed = (id: number) =>
58	    setCollapsed((s) => {
59	      const n = new Set(s);
60	      if (n.has(id)) n.delete(id);
61	      else n.add(id);
62	      return n;
63	    });
64	
65	  const byProject = (pid: number | null) =>
66	    props.conversations.filter((c) => (c.project_id ?? null) === pid);
67	
68	  const drop = (e: React.DragEvent, target: number | null) => {
69	    e.preventDefault();
70	    setDropTarget(null);
71	    const id = Number(e.dataTransfer.getData("text/conv"));
72	    if (id) props.onMoveConv(id, target);
73	  };
74	
75	  const renderConv = (c: ConversationDto) => (
76	    <div
77	      key={c.id}
78	      className={`conv-item ${
79	        props.activeConvId === c.id && props.view === "chat" ? "active" : ""
80	      }`}
81	      draggable={renaming !== c.id}
82	      onDragStart={(e) => e.dataTransfer.setData("text/conv", String(c.id))}
83	      onClick={() => props.onSelectConv(c.id)}
84	      onDoubleClick={() => {
85	        setRenaming(c.id);
86	        setRenameBuf(c.title);
87	      }}
88	    >
89	      {renaming === c.id ? (
90	        <input
91	          autoFocus
92	          className="rail-inline-input"
93	          value={renameBuf}
94	          onChange={(e) => setRenameBuf(e.target.value)}
95	          onBlur={() => commitRename(c.id)}
96	          onKeyDown={(e) => {
97	            if (e.key === "Enter") commitRename(c.id);
98	            if (e.key === "Escape") setRenaming(null);
99	          }}
100	          onClick={(e) => e.stopPropagation()}
101	        />
102	      ) : (
103	        <>
104	          {c.runtime && (
105	            <span className={`conv-rt rt-${c.runtime}`} title={c.runtime}>
106	              {RT_BADGE[c.runtime] ?? "··"}
107	            </span>
108	          )}
109	          <span className="title">{c.title}</span>
110	          <span
111	            className={`pin ${c.pinned ? "on" : ""}`}
112	            title={c.pinned ? "Unpin" : "Pin"}
113	            onClick={(e) => {
114	              e.stopPropagation();
115	              props.onPin(c.id, !c.pinned);
116	            }}
117	          >
118	            ★
119	          </span>
120	          <span
121	            className="pin"
122	            title="Delete"
123	            onClick={(e) => {
124	              e.stopPropagation();
125	              if (confirm(`Delete "${c.title}"?`)) props.onDelete(c.id);
126	            }}
127	          >
128	            ✕
129	          </span>
130	        </>
131	      )}
132	    </div>
133	  );
134	
135	  return (
136	    <div className="rail">
137	      <div className="rail-search">
138	        <input placeholder="Search…" onChange={(e) => props.onSearch(e.target.value)} />
139	      </div>
140	
141	      <div className="rail-section">Workspace</div>
142	      {NAV.map((n) => (
143	        <div
144	          key={n.key}
145	          className={`nav-item ${props.view === n.key ? "active" : ""}`}
146	          onClick={() => props.setView(n.key)}
147	        >
148	          <span className="ico">{n.ico}</span>
149	          {n.label}
150	        </div>
151	      ))}
152	
153	      <div className="conv-list">
154	        {/* Projects */}
155	        <div className="rail-section">
156	          <span>Projects</span>
157	          <span
158	            className="icon-btn"
159	            title="New project"
160	            style={{ cursor: "pointer" }}
161	            onClick={props.onCreateProject}
162	          >
163	            +
164	          </span>
165	        </div>
166	        {props.projects.map((p) => {
167	          const convs = byProject(p.id);
168	          const isCollapsed = collapsed.has(p.id);
169	          return (
170	            <div key={p.id} className="project-group">
171	              <div
172	                className={`project-header ${dropTarget === p.id ? "drop" : ""}`}
173	                onDragOver={(e) => {
174	                  e.preventDefault();
175	                  setDropTarget(p.id);
176	                }}
177	                onDragLeave={() => setDropTarget(null)}
178	                onDrop={(e) => drop(e, p.id)}
179	                onClick={() => toggleCollapsed(p.id)}
180	                onDoubleClick={() => {
181	                  setRenamingProject(p.id);
182	                  setProjBuf(p.name);
183	                }}
184	              >
185	                <span className="proj-caret">{isCollapsed ? "▸" : "▾"}</span>
186	                {renamingProject === p.id ? (
187	                  <input
188	                    autoFocus
189	                    className="rail-inline-input"
190	                    value={projBuf}
191	                    onChange={(e) => setProjBuf(e.target.value)}
192	                    onBlur={() => commitProjectRename(p.id)}
193	                    onKeyDown={(e) => {
194	                      if (e.key === "Enter") commitProjectRename(p.id);
195	                      if (e.key === "Escape") setRenamingProject(null);
196	                    }}
197	                    onClick={(e) => e.stopPropagation()}
198	                  />
199	                ) : (
200	                  <>
201	                    <span className="proj-name">{p.name}</span>
202	                    <span className="proj-count">{convs.length}</span>
203	                    <span
204	                      className={`pin ${p.pinned ? "on" : ""}`}
205	                      title={p.pinned ? "Unpin" : "Pin"}
206	                      onClick={(e) => {
207	                        e.stopPropagation();
208	                        props.onPinProject(p.id, !p.pinned);
209	                      }}
210	                    >
211	                      ★
212	                    </span>
213	                    <span
214	                      className="pin"
215	                      title="Delete project"
216	                      onClick={(e) => {
217	                        e.stopPropagation();
218	                        if (confirm(`Delete project "${p.name}"? Its chats are kept.`))
219	                          props.onDeleteProject(p.id);
220	                      }}
221	                    >
222	                      ✕
223	                    </span>
224	                  </>
225	                )}
226	              </div>
227	              {!isCollapsed && (
228	                <div className="project-chats">{convs.map(renderConv)}</div>
229	              )}
230	            </div>
231	          );
232	        })}
233	
234	        {/* Loose conversations */}
235	        <div
236	          className={`rail-section drop-zone ${dropTarget === "loose" ? "drop" : ""}`}
237	          onDragOver={(e) => {
238	            e.preventDefault();
239	            setDropTarget("loose");
240	          }}
241	          onDragLeave={() => setDropTarget(null)}
242	          onDrop={(e) => drop(e, null)}
243	        >
244	          <span>Conversations</span>
245	          <span
246	            className="icon-btn"
247	            title="New chat"
248	            style={{ cursor: "pointer" }}
249	            onClick={props.onNewChat}
250	          >
251	            +
252	          </span>
253	        </div>
254	        {byProject(null).map(renderConv)}
255	      </div>
256	
257	      <div className="rail-footer">
258	        <div className="nav-item" onClick={props.onOpenSettings}>
259	          <span className="ico">⚙</span>
260	          Settings
261	        </div>
262	      </div>
263	    </div>
264	  );
265	}
