    pub fn delete_conversation(&self, id: i64) {
        // Use a transaction so both deletes succeed or both fail
        if let Ok(tx) = self.conn.unchecked_transaction() {
            let r1 = tx.execute(
                "DELETE FROM messages WHERE conversation_id = ?1",
                params![id],
            );
