import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useRef,
  useState,
  type ReactNode,
} from "react";

// In-app replacements for window.confirm / window.prompt, which don't render
// reliably inside the Tauri (WKWebView) webview. Exposed as async functions
// via the useDialog() hook.

interface ConfirmOpts {
  title?: string;
  confirmText?: string;
  cancelText?: string;
  danger?: boolean;
}
interface PromptOpts {
  title?: string;
  defaultValue?: string;
  placeholder?: string;
  confirmText?: string;
}

type Req =
  | {
      kind: "confirm";
      message: string;
      opts: ConfirmOpts;
      resolve: (v: boolean) => void;
    }
  | {
      kind: "prompt";
      message: string;
      opts: PromptOpts;
      resolve: (v: string | null) => void;
    };

interface DialogApi {
  confirm: (message: string, opts?: ConfirmOpts) => Promise<boolean>;
  prompt: (message: string, opts?: PromptOpts) => Promise<string | null>;
}

const DialogContext = createContext<DialogApi | null>(null);

export function useDialog(): DialogApi {
  const ctx = useContext(DialogContext);
  if (!ctx) throw new Error("useDialog must be used within a DialogProvider");
  return ctx;
}

export function DialogProvider({ children }: { children: ReactNode }) {
  const [req, setReq] = useState<Req | null>(null);
  const [input, setInput] = useState("");
  const inputRef = useRef<HTMLInputElement>(null);

  const confirm = useCallback(
    (message: string, opts: ConfirmOpts = {}) =>
      new Promise<boolean>((resolve) =>
        setReq({ kind: "confirm", message, opts, resolve }),
      ),
    [],
  );
  const prompt = useCallback(
    (message: string, opts: PromptOpts = {}) =>
      new Promise<string | null>((resolve) => {
        setInput(opts.defaultValue ?? "");
        setReq({ kind: "prompt", message, opts, resolve });
      }),
    [],
  );

  const cancelValue = (r: Req) => (r.kind === "confirm" ? false : null);

  const close = (value: boolean | string | null) => {
    setReq((r) => {
      if (!r) return null;
      if (r.kind === "confirm") r.resolve(value as boolean);
      else r.resolve(value as string | null);
      return null;
    });
  };

  // Focus the prompt input when it opens.
  useEffect(() => {
    if (req?.kind === "prompt") {
      const t = setTimeout(() => inputRef.current?.focus(), 0);
      return () => clearTimeout(t);
    }
  }, [req]);

  // Esc cancels; Enter confirms a confirm dialog. Capture phase so this wins
  // over other global Esc handlers (dock, settings) while a dialog is open.
  useEffect(() => {
    if (!req) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        e.preventDefault();
        e.stopPropagation();
        close(cancelValue(req));
      } else if (e.key === "Enter" && req.kind === "confirm") {
        e.preventDefault();
        e.stopPropagation();
        close(true);
      }
    };
    window.addEventListener("keydown", onKey, true);
    return () => window.removeEventListener("keydown", onKey, true);
  }, [req]);

  return (
    <DialogContext.Provider value={{ confirm, prompt }}>
      {children}
      {req && (
        <div className="modal-backdrop" onClick={() => close(cancelValue(req))}>
          <div
            className="modal dialog-modal"
            onClick={(e) => e.stopPropagation()}
          >
            {req.opts.title && <h2>{req.opts.title}</h2>}
            <p className="dialog-message">{req.message}</p>
            {req.kind === "prompt" && (
              <input
                ref={inputRef}
                className="dialog-input"
                value={input}
                placeholder={req.opts.placeholder}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter" && input.trim()) {
                    e.preventDefault();
                    close(input);
                  }
                }}
              />
            )}
            <div className="modal-actions">
              <button className="tbtn" onClick={() => close(cancelValue(req))}>
                {req.opts.cancelText ?? "Cancel"}
              </button>
              <button
                className={`tbtn ${
                  req.kind === "confirm" && req.opts.danger ? "danger" : "accent"
                }`}
                disabled={req.kind === "prompt" && !input.trim()}
                onClick={() => close(req.kind === "confirm" ? true : input)}
              >
                {req.opts.confirmText ?? (req.kind === "confirm" ? "OK" : "Save")}
              </button>
            </div>
          </div>
        </div>
      )}
    </DialogContext.Provider>
  );
}

