async fn maybe_auto_title(
    state: &State<'_, AppState>,
    conversation_id: i64,
    gp: &GenParams,
    user_text: &str,
) {
    let needs = {
        let storage = state.storage.lock().unwrap();
        storage.needs_auto_title(conversation_id)
    };
    if !needs {
        return;
    }
    let api_key = state.api_key_for(&gp.endpoint);
    let prompt = vec![
        Message::text(
            Role::System,
            "Give a concise 3-6 word title for this conversation. Reply with only the title, no quotes."
                .to_string(),
        ),
        Message::text(Role::User, user_text.to_string()),
    ];
    let title = api::complete_once(
        &gp.endpoint,
        &gp.model,
        &prompt,
        api_key.as_deref(),
        Some(32),
        Some(0.3),
    )
    .await;
    if let Ok(raw) = title {
        let clean = crate::markdown::strip_reasoning(&raw);
        let clean = clean.trim().trim_matches('"').trim();
        if !clean.is_empty() {
            let storage = state.storage.lock().unwrap();
            storage.update_conversation_title(conversation_id, clean);
            storage.mark_auto_titled(conversation_id);
        }
    }
}

/// Returns true if the conversation has not yet been auto-titled. Used
/// to gate the one-shot auto-title call so manual renames stick.
pub fn needs_auto_title(&self, id: i64) -> bool {
    self.conn
        .query_row(
            "SELECT auto_titled FROM conversations WHERE id = ?1",
            params![id],
            |row| row.get::<_, i64>(0),
        )
        .map(|v| v == 0)
        .unwrap_or(false)
}

pub fn mark_auto_titled(&self, id: i64) {
    self.conn
        .execute(
            "UPDATE conversations SET auto_titled = 1 WHERE id = ?1",
            params![id],
        )
        .ok();

